  1	import * as React from 'react';
  2	import { UploadFile } from '@odf/shared/file-handling';
  3	import { PasswordInput } from '@odf/shared/text-inputs';
  4	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  5	import {
  6	  FormGroup,
  7	  Checkbox,
  8	  TextInput,
  9	  Form,
 10	  GridItem,
 11	  Grid,
 12	  Text,
 13	  TextVariants,
 14	  Stack,
 15	} from '@patternfly/react-core';
 16	import { WizardDispatch, WizardState } from '../../../reducer';
 17	import '../backing-storage-step.scss';
 18	
 19	const updatePrivateTlsFile = (dispatch: WizardDispatch, file: File) => {
 20	  dispatch({
 21	    type: 'advancedSettings/externalPostgres/tls/keys/setPrivateKey',
 22	    payload: file,
 23	  });
 24	};
 25	
 26	const updatePublicTlsFile = (dispatch: WizardDispatch, file: File) => {
 27	  dispatch({
 28	    type: 'advancedSettings/externalPostgres/tls/keys/setPublicKey',
 29	    payload: file,
 30	  });
 31	};
 32	
 33	export const PostgresConnectionDetails: React.FC<
 34	  PostgresConnectionDetailsProps
 35	> = ({
 36	  dispatch,
 37	  username,
 38	  password,
 39	  serverName,
 40	  port,
 41	  databaseName,
 42	  tlsEnabled,
 43	  allowSelfSignedCerts,
 44	  enableClientSideCerts,
 45	  tlsFiles,
 46	}) => {
 47	  const { t } = useCustomTranslation();
 48	
 49	  const processKeys = React.useCallback(
 50	    (keyFiles: File[]) => {
 51	      if (keyFiles.some((file) => file.name.startsWith('private'))) {
 52	        updatePrivateTlsFile(
 53	          dispatch,
 54	          keyFiles.find((file) => file.name.startsWith('private'))
 55	        );
 56	      } else {
 57	        updatePrivateTlsFile(dispatch, null);
 58	      }
 59	
 60	      if (keyFiles.some((file) => file.name.startsWith('public'))) {
 61	        updatePublicTlsFile(
 62	          dispatch,
 63	          keyFiles.find((file) => file.name.startsWith('public'))
 64	        );
 65	      } else {
 66	        updatePublicTlsFile(dispatch, null);
 67	      }
 68	    },
 69	    [dispatch]
 70	  );
 71	
 72	  return (
 73	    <Form>
 74	      <Text component={TextVariants.h4}>{t('Connection details')}</Text>
 75	      <Grid hasGutter>
 76	        <GridItem span={6}>
 77	          <FormGroup
 78	            label={t('Username')}
 79	            fieldId="external-postgres-username"
 80	            isRequired
 81	          >
 82	            <TextInput
 83	              id="external-postgres-username-input"
 84	              type="text"
 85	              value={username}
 86	              onChange={(_event, newUsername: string) => {
 87	                dispatch({
 88	                  type: 'advancedSettings/externalPostgres/setUsername',
 89	                  payload: newUsername,
 90	                });
 91	              }}
 92	              isRequired
 93	            />
 94	          </FormGroup>
 95	        </GridItem>
 96	        <GridItem span={6} />
 97	        <GridItem span={6}>
 98	          <FormGroup
 99	            label={t('Password')}
100	            fieldId="external-postgres-password"
101	            isRequired
102	          >
103	            <PasswordInput
104	              id={'external-postgres-password-input'}
105	              value={password}
106	              onChange={(newPassword: string) => {
107	                dispatch({
108	                  type: 'advancedSettings/externalPostgres/setPassword',
109	                  payload: newPassword,
110	                });
111	              }}
112	              isRequired
113	            />
114	          </FormGroup>
115	        </GridItem>
116	        <GridItem span={6} />
117	        <GridItem span={5}>
118	          <FormGroup
119	            label={t('Server name')}
120	            fieldId="external-postgres-server-tls"
121	            isRequired
122	          >
123	            <TextInput
124	              id="external-postgres-server-input"
125	              type="text"
126	              value={serverName}
127	              onChange={(_event, newServer: string) => {
128	                dispatch({
129	                  type: 'advancedSettings/externalPostgres/setServerName',
130	                  payload: newServer,
131	                });
132	              }}
133	              isRequired
134	            />
135	          </FormGroup>
136	        </GridItem>
137	        <GridItem span={1}>
138	          <FormGroup
139	            label={t('Port')}
140	            fieldId="external-postgres-port"
141	            isRequired
142	          >
143	            <TextInput
144	              id="external-postgres-port-input"
145	              type="number"
146	              value={port}
147	              onChange={(_event, newPort: string) => {
148	                dispatch({
149	                  type: 'advancedSettings/externalPostgres/setPort',
150	                  payload: newPort,
151	                });
152	              }}
153	              isRequired
154	            />
155	          </FormGroup>
156	        </GridItem>
157	        <GridItem span={6} />
158	        <GridItem span={6}>
159	          <FormGroup
160	            label={t('Database name')}
161	            fieldId="external-postgres-database-tls"
162	            isRequired
163	          >
164	            <TextInput
165	              id="external-postgres-database-input"
166	              type="text"
167	              value={databaseName}
168	              onChange={(_event, newDatabase: string) => {
169	                dispatch({
170	                  type: 'advancedSettings/externalPostgres/setDatabaseName',
171	                  payload: newDatabase,
172	                });
173	              }}
174	              isRequired
175	            />
176	          </FormGroup>
177	        </GridItem>
178	        <GridItem span={6} />
179	        <GridItem className="odf-backing-store__tls--margin-top">
180	          <FormGroup fieldId="external-postgres-enable-tls">
181	            <Checkbox
182	              id="external-postgres-enable-tls"
183	              label={t('Enable TLS/SSL')}
184	              description={t(
185	                'Enable this for encrytion on flight with the Postgres server'
186	              )}
187	              isChecked={tlsEnabled}
188	              onChange={() => {
189	                const isTLSEnabled = !tlsEnabled;
190	                dispatch({
191	                  type: 'advancedSettings/externalPostgres/tls/enableTLS',
192	                  payload: !tlsEnabled,
193	                });
194	
195	                dispatch({
196	                  type: 'advancedSettings/externalPostgres/tls/allowSelfSignedCerts',
197	                  payload:
198	                    !isTLSEnabled && allowSelfSignedCerts
199	                      ? false
200	                      : allowSelfSignedCerts,
201	                });
202	
203	                dispatch({
204	                  type: 'advancedSettings/externalPostgres/tls/enableClientSideCerts',
205	                  payload:
206	                    !isTLSEnabled && enableClientSideCerts
207	                      ? false
208	                      : enableClientSideCerts,
209	                });
210	              }}
211	              className="odf-backing-store__radio--margin-bottom"
212	            />
213	            {tlsEnabled && (
214	              <Stack className="odf-backing-store__ssl" hasGutter>
215	                <Checkbox
216	                  id="external-postgres-allow-self-signed-certs"
217	                  label={t('Allow self-signed certificates')}
218	                  description={t(
219	                    'Adding this option will allow the postgres server to use a self-signed certificates.'
220	                  )}
221	                  isChecked={allowSelfSignedCerts}
222	                  onChange={() =>
223	                    dispatch({
224	                      type: 'advancedSettings/externalPostgres/tls/allowSelfSignedCerts',
225	                      payload: !allowSelfSignedCerts,
226	                    })
227	                  }
228	                />
229	                <Checkbox
230	                  id="external-postgres-enable-client-side-certs"
231	                  label={t('Enable client-side certificates')}
232	                  description={t(
233	                    'Select this option to upload and use your client side certificates'
234	                  )}
235	                  isChecked={enableClientSideCerts}
236	                  onChange={() => {
237	                    dispatch({
238	                      type: 'advancedSettings/externalPostgres/tls/enableClientSideCerts',
239	                      payload: !enableClientSideCerts,
240	                    });
241	
242	                    dispatch({
243	                      type: 'advancedSettings/externalPostgres/tls/keys/setPrivateKey',
244	                      payload: null,
245	                    });
246	
247	                    dispatch({
248	                      type: 'advancedSettings/externalPostgres/tls/keys/setPublicKey',
249	                      payload: null,
250	                    });
251	                  }}
252	                />
253	              </Stack>
254	            )}
255	            {enableClientSideCerts && (
256	              <UploadFile
257	                acceptedFiles=".pem, .key, .crt"
258	                infoText={t('Accepted file types: .pem, .crt, .key')}
259	                titleText={t(
260	                  'Files should be named private and public followed by compatible extensions'
261	                )}
262	                onFileUpload={processKeys}
263	                uploadLimit={2}
264	                uploadedFiles={tlsFiles}
265	                compatibleFileFilter={(file) =>
266	                  file.name.startsWith('private') ||
267	                  file.name.startsWith('public')
268	                }
269	              />
270	            )}
271	          </FormGroup>
272	        </GridItem>
273	      </Grid>
274	    </Form>
275	  );
276	};
277	
278	type PostgresConnectionDetailsProps = {
279	  dispatch: WizardDispatch;
280	  username: WizardState['advancedSettings']['externalPostgres']['username'];
281	  password: WizardState['advancedSettings']['externalPostgres']['password'];
282	  serverName: WizardState['advancedSettings']['externalPostgres']['serverName'];
283	  port: WizardState['advancedSettings']['externalPostgres']['port'];
284	  databaseName: WizardState['advancedSettings']['externalPostgres']['databaseName'];
285	  tlsEnabled: WizardState['advancedSettings']['externalPostgres']['tls']['enabled'];
286	  allowSelfSignedCerts: WizardState['advancedSettings']['externalPostgres']['tls']['allowSelfSignedCerts'];
287	  enableClientSideCerts: WizardState['advancedSettings']['externalPostgres']['tls']['enableClientSideCerts'];
288	  tlsFiles: File[];
289	};

